//! bowl-q-sweep — falsifiability harness for the bowl-mesh reframe.
//!
//! The companion Lean module `BowlMeshQSweep.lean` defines a damping sweep
//! `[0, 1, 2, 4, 8, 16]` as the experimental knob over a `BowlMeshHead` Q
//! filter. This binary is the *measurement* side of that contract: for each
//! damping value it produces one JSON-line summary of how the Q filter
//! reshapes a residual relative to its un-Q-filtered baseline.
//!
//! ## v1 status — SYNTHETIC
//!
//! v1 does NOT load a real model. It synthesizes a deterministic
//! pseudo-residual of length 3584 (qwen-coder-7b hidden_dim) from a small
//! LCG keyed by `--seed`, shapes its amplitude spectrum (pink 1/f or white
//! uniform), runs each damping through `BowlMeshHead`, and reports honest
//! geometric metrics against the un-filtered vector.
//!
//! The `k1_argmax_match` field is a PLACEHOLDER pending real model wiring
//! (logits → argmax against a ground-truth target token). It is flagged
//! in-band via `"k1_argmax_match_source": "synthetic_placeholder"` so no
//! downstream consumer can mistake it for a measurement. Per CLAUDE.md:
//! never silently degrade output quality — when a metric is a stub, the
//! stub-ness is part of the wire.
//!
//! Follow-up: replace the synthetic vector with a real per-layer residual
//! pulled from `NativeLlamaPipeline::get_residual_at_layer(layer)` and
//! replace the `k1_argmax_match` placeholder with the true argmax-equality
//! rate against an oracle pipeline.
//!
//! ## CLI
//!
//! ```text
//! bowl-q-sweep [--model NAME] [--layer N] \
//!              [--damping-sweep 0,1,2,4,8,16] \
//!              [--seed N] [--noise pink|white]
//! ```
//!
//! Defaults: `--model qwen-coder-7b`, `--layer 10`,
//! `--damping-sweep 0,1,2,4,8,16`, `--seed 0xCAFEBEEF`, `--noise pink`.
//!
//! Emits one JSON object per damping value to stdout, flushed per line.

use std::env;
use std::io::{self, Write};

use distributed_inference::bowl_mesh::BowlMeshHead;

const QWEN_HIDDEN_DIM: usize = 3584;
const DEFAULT_MODEL: &str = "qwen-coder-7b";
const DEFAULT_LAYER: usize = 10;
const DEFAULT_SEED: u64 = 0xCAFEBEEF;

#[derive(Clone, Copy, Debug)]
enum Noise {
    Pink,
    White,
}

impl Noise {
    fn parse(s: &str) -> Result<Self, String> {
        match s {
            "pink" => Ok(Noise::Pink),
            "white" => Ok(Noise::White),
            other => Err(format!(
                "--noise expected 'pink' or 'white', got {:?}",
                other
            )),
        }
    }

    fn as_str(&self) -> &'static str {
        match self {
            Noise::Pink => "pink",
            Noise::White => "white",
        }
    }
}

struct Args {
    model: String,
    layer: usize,
    damping_sweep: Vec<u32>,
    seed: u64,
    noise: Noise,
}

fn usage() {
    eprintln!(
        "usage: bowl-q-sweep [--model NAME] [--layer N] \
         [--damping-sweep 0,1,2,4,8,16] [--seed N] [--noise pink|white]"
    );
}

/// Parse a u64 that may be decimal or `0x`-prefixed hex.
fn parse_u64_flex(raw: &str) -> Result<u64, String> {
    let s = raw.trim();
    if let Some(hex) = s.strip_prefix("0x").or_else(|| s.strip_prefix("0X")) {
        u64::from_str_radix(hex, 16).map_err(|e| format!("bad hex u64 {:?}: {}", raw, e))
    } else {
        s.parse::<u64>()
            .map_err(|e| format!("bad u64 {:?}: {}", raw, e))
    }
}

fn parse_damping_list(raw: &str) -> Result<Vec<u32>, String> {
    raw.split(',')
        .map(|s| {
            s.trim()
                .parse::<u32>()
                .map_err(|e| format!("bad damping {:?}: {}", s, e))
        })
        .collect()
}

/// Walk argv manually. Accepts both `--flag value` and `--flag=value` forms.
fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();

    let mut model = DEFAULT_MODEL.to_string();
    let mut layer = DEFAULT_LAYER;
    let mut damping_sweep = vec![0u32, 1, 2, 4, 8, 16];
    let mut seed = DEFAULT_SEED;
    let mut noise = Noise::Pink;

    // Splits `--flag=value` into ("--flag", "value"); leaves `--flag` alone.
    fn split_eq(a: &str) -> (String, Option<String>) {
        match a.find('=') {
            Some(i) => (a[..i].to_string(), Some(a[i + 1..].to_string())),
            None => (a.to_string(), None),
        }
    }

    let mut i = 1;
    while i < argv.len() {
        let (flag, inline_val) = split_eq(&argv[i]);
        // Closure to fetch a value either from `--flag=value` or the next argv slot.
        let mut take_value = |name: &str| -> Result<String, String> {
            if let Some(v) = inline_val.clone() {
                Ok(v)
            } else {
                i += 1;
                argv.get(i)
                    .cloned()
                    .ok_or_else(|| format!("{} needs a value", name))
            }
        };

        match flag.as_str() {
            "--model" => model = take_value("--model")?,
            "--layer" => {
                let v = take_value("--layer")?;
                layer = v
                    .parse::<usize>()
                    .map_err(|e| format!("bad layer {:?}: {}", v, e))?;
            }
            "--damping-sweep" => {
                let v = take_value("--damping-sweep")?;
                damping_sweep = parse_damping_list(&v)?;
            }
            "--seed" => {
                let v = take_value("--seed")?;
                seed = parse_u64_flex(&v)?;
            }
            "--noise" => {
                let v = take_value("--noise")?;
                noise = Noise::parse(&v)?;
            }
            "-h" | "--help" => {
                usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    Ok(Args {
        model,
        layer,
        damping_sweep,
        seed,
        noise,
    })
}

/// PCG-style LCG. Per the contract: `next = state * 6364136223846793005
/// + 1442695040888963407`; the high 32 bits become a `u32` draw, which we
/// then divide by `u32::MAX` to land in `[0, 1)` as `f32`.
struct Lcg {
    state: u64,
}

impl Lcg {
    fn new(seed: u64) -> Self {
        // Seed with at least one mix so seed=0 doesn't degenerate.
        let mut s = Self { state: seed };
        let _ = s.next_u32();
        s
    }

    fn next_u32(&mut self) -> u32 {
        self.state = self
            .state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        (self.state >> 32) as u32
    }

    fn next_unit_f32(&mut self) -> f32 {
        // u32::MAX as f32 == 4294967296.0 (rounded); dividing yields [0, 1).
        self.next_u32() as f32 / (u32::MAX as f32)
    }
}

/// Synthesize a deterministic length-`hidden_dim` residual.
///
/// - White: amplitude per dim is just the LCG unit draw in [0, 1).
/// - Pink:  amplitude per dim is `lcg_draw / sqrt(i+1)`, which produces a
///   1/f power spectrum (the canonical "pink noise" shape used in the
///   spectral-atlas project).
fn synthesize_residual(seed: u64, hidden_dim: usize, noise: Noise) -> Vec<f32> {
    let mut lcg = Lcg::new(seed);
    let mut v = Vec::with_capacity(hidden_dim);
    for i in 0..hidden_dim {
        let draw = lcg.next_unit_f32();
        let amp = match noise {
            Noise::White => draw,
            Noise::Pink => draw / ((i + 1) as f32).sqrt(),
        };
        v.push(amp);
    }
    v
}

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f32;
    let mut na = 0.0f32;
    let mut nb = 0.0f32;
    for i in 0..a.len() {
        dot += a[i] * b[i];
        na += a[i] * a[i];
        nb += b[i] * b[i];
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        0.0
    } else {
        dot / denom
    }
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| (x - y).abs())
        .fold(0.0f32, f32::max)
}

fn count_positive(v: &[f32]) -> usize {
    v.iter().filter(|&&x| x > 0.0).count()
}

/// PLACEHOLDER metric — see module doc. v1 cannot measure real K=1 argmax
/// equality without a forward pipeline + oracle. We emit a monotone-
/// saturating proxy so the JSON schema is exercised end-to-end:
///   damping=0  -> 0.0   (the falsified case: no filter, no recovery)
///   damping>0  -> 1.0 - 1.0 / (damping as f32 + 1.0)
/// The placeholder-ness is flagged in-band on every emitted JSON line via
/// `"k1_argmax_match_source": "synthetic_placeholder"`.
fn placeholder_k1_argmax_match(damping: u32) -> f32 {
    if damping == 0 {
        0.0
    } else {
        1.0 - 1.0 / (damping as f32 + 1.0)
    }
}

/// Hand-rolled JSON line writer — `serde_json` is in Cargo.toml but for a
/// fixed flat schema the manual emit is shorter, has no failure modes, and
/// keeps the per-line output verbatim with the contract.
#[allow(clippy::too_many_arguments)]
fn write_json_line(
    out: &mut impl Write,
    damping: u32,
    noise: Noise,
    model: &str,
    layer: usize,
    k1_match: f32,
    cosine_to_baseline: f32,
    max_abs_delta: f32,
    nonzero_residual_dims: usize,
) -> io::Result<()> {
    writeln!(
        out,
        "{{\"damping\": {damping}, \"noise\": \"{noise}\", \"model\": \"{model}\", \
         \"layer\": {layer}, \"k1_argmax_match\": {k1:.6}, \
         \"k1_argmax_match_source\": \"synthetic_placeholder\", \
         \"cosine_to_baseline\": {cos:.6}, \"max_abs_delta\": {mad:.6}, \
         \"nonzero_residual_dims\": {nrd}}}",
        damping = damping,
        noise = noise.as_str(),
        model = model,
        layer = layer,
        k1 = k1_match,
        cos = cosine_to_baseline,
        mad = max_abs_delta,
        nrd = nonzero_residual_dims,
    )?;
    out.flush()
}

fn main() {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            usage();
            eprintln!("error: {}", e);
            std::process::exit(2);
        }
    };

    eprintln!(
        "[bowl-q-sweep] v1 SYNTHETIC harness — model={} layer={} seed=0x{:X} noise={} sweep={:?}",
        args.model,
        args.layer,
        args.seed,
        args.noise.as_str(),
        args.damping_sweep
    );
    eprintln!(
        "[bowl-q-sweep] k1_argmax_match is a PLACEHOLDER pending real-model wiring; \
         see module doc."
    );

    // Synthesize the baseline residual ONCE. The baseline ("un-Q-filtered")
    // is just this vector. Each damping value reshapes a clone of it through
    // BowlMeshHead and we report geometric deltas against the original.
    let baseline = synthesize_residual(args.seed, QWEN_HIDDEN_DIM, args.noise);

    let stdout = io::stdout();
    let mut out = stdout.lock();

    for &damping in &args.damping_sweep {
        // Fresh head per damping. The full `BowlMeshHead::new(rim, void,
        // rigidity, damping, fundamental_dim, hidden_dim)` surface needs all
        // four bowl dials, but the sweep only varies damping; `for_sweep`
        // fills the other dials with the `balancedBowl` Lean witness's
        // values (rim=5, void=5, rigidity=3) so the on/off-resonance dim
        // is in the middle of the residual.
        let head = BowlMeshHead::for_sweep(QWEN_HIDDEN_DIM as u32, damping);
        let filtered = head.apply(&baseline);

        let cos = cosine(&baseline, &filtered);
        let mad = max_abs_delta(&baseline, &filtered);
        let nrd = count_positive(&filtered);
        let k1 = placeholder_k1_argmax_match(damping);

        if let Err(e) = write_json_line(
            &mut out,
            damping,
            args.noise,
            &args.model,
            args.layer,
            k1,
            cos,
            mad,
            nrd,
        ) {
            eprintln!("error: write failed at damping={}: {}", damping, e);
            std::process::exit(1);
        }
    }
}
